+    let cmd = format!("command -v {tool} >/dev/null 2>&1 && {tool} --version 2>&1 | head -1");
+    let result = client.execute(&cmd).await.ok()?;
+    if result.exit_code != 0 {
+        return None;
+    }
+    result
+        .stdout
+        .lines()
+        .next()
+        .map(|line| line.trim().to_string())
+        .filter(|line| !line.is_empty())
+}
